import React from 'react';
import { BrowserRouter, Navigate, Route, Routes } from 'react-router-dom';

import { AuthProvider, useAuth } from './auth/AuthContext';
import ProtectedRoute from './components/ProtectedRoute';
import MainLayout from './layouts/MainLayout';
import DonorLayout from './layouts/DonorLayout';
import AdminLayout from './layouts/AdminLayout';
import PublicLayout from './layouts/PublicLayout';
import LandingPage from './pages/LandingPage';
import AboutPage from './pages/AboutPage';
import HowItWorksPage from './pages/HowItWorksPage';
import ContactPage from './pages/ContactPage';
import EligibilityPage from './pages/EligibilityPage';
import AuthPage from './pages/AuthPage';
import VerifyPage from './pages/VerifyPage';
import DashboardPage from './pages/DashboardPage';
import DonorPage from './pages/DonorPage';
import RecipientPage from './pages/RecipientPage';
import NotificationsPage from './pages/NotificationsPage';
import AdminPage from './pages/AdminPage';
import NotFoundPage from './pages/NotFoundPage';

import './App.css';

function PortalRedirect() {
  const { auth } = useAuth();
  if (!auth?.token) {
    return <Navigate to="/auth" replace />;
  }

  if (auth?.user?.role === 'ADMIN') {
    return <Navigate to="/admin/overview" replace />;
  }

  if (auth?.user?.role === 'DONOR') {
    return <Navigate to="/donor/overview" replace />;
  }

  if (auth?.user?.role === 'RECIPIENT') {
    return <Navigate to="/recipient" replace />;
  }

  return <Navigate to="/dashboard" replace />;
}

function ProtectedLayout({ children, roles }) {
  const { role } = useAuth();

  if (role === 'ADMIN' && !(roles || []).includes('ADMIN')) {
    return <Navigate to="/admin/overview" replace />;
  }

  return (
    <ProtectedRoute roles={roles}>
      <MainLayout>{children}</MainLayout>
    </ProtectedRoute>
  );
}

function DonorWebsiteLayout({ children }) {
  return (
    <ProtectedRoute roles={['DONOR']}>
      <DonorLayout>{children}</DonorLayout>
    </ProtectedRoute>
  );
}

function AdminWebsiteLayout({ children }) {
  return (
    <ProtectedRoute roles={['ADMIN']}>
      <AdminLayout>{children}</AdminLayout>
    </ProtectedRoute>
  );
}

function DashboardRoute() {
  const { role } = useAuth();

  if (role === 'DONOR') {
    return <Navigate to="/donor/overview" replace />;
  }

  if (role === 'ADMIN') {
    return <Navigate to="/admin/overview" replace />;
  }

  if (role === 'RECIPIENT') {
    return <Navigate to="/recipient" replace />;
  }

  return (
    <ProtectedLayout>
      <DashboardPage />
    </ProtectedLayout>
  );
}

function AppRoutes() {
  return (
    <Routes>
      <Route
        path="/"
        element={(
          <PublicLayout>
            <LandingPage />
          </PublicLayout>
        )}
      />
      <Route
        path="/about"
        element={(
          <PublicLayout>
            <AboutPage />
          </PublicLayout>
        )}
      />
      <Route
        path="/how-it-works"
        element={(
          <PublicLayout>
            <HowItWorksPage />
          </PublicLayout>
        )}
      />
      <Route
        path="/contact"
        element={(
          <PublicLayout>
            <ContactPage />
          </PublicLayout>
        )}
      />
      <Route
        path="/eligibility"
        element={(
          <PublicLayout>
            <EligibilityPage />
          </PublicLayout>
        )}
      />

      <Route path="/portal" element={<PortalRedirect />} />
      <Route path="/auth" element={<AuthPage />} />

      <Route
        path="/dashboard"
        element={<DashboardRoute />}
      />

      <Route
        path="/verify"
        element={(
          <ProtectedLayout>
            <VerifyPage />
          </ProtectedLayout>
        )}
      />

      <Route
        path="/donor"
        element={<Navigate to="/donor/overview" replace />}
      />

      <Route
        path="/donor/overview"
        element={(
          <DonorWebsiteLayout>
            <DonorPage view="overview" />
          </DonorWebsiteLayout>
        )}
      />

      <Route
        path="/donor/profile"
        element={(
          <DonorWebsiteLayout>
            <DonorPage view="profile" />
          </DonorWebsiteLayout>
        )}
      />

      <Route
        path="/donor/availability"
        element={(
          <DonorWebsiteLayout>
            <DonorPage view="availability" />
          </DonorWebsiteLayout>
        )}
      />

      <Route
        path="/donor/requests"
        element={(
          <DonorWebsiteLayout>
            <DonorPage view="requests" />
          </DonorWebsiteLayout>
        )}
      />

      <Route
        path="/donor/matches"
        element={(
          <DonorWebsiteLayout>
            <DonorPage view="matches" />
          </DonorWebsiteLayout>
        )}
      />

      <Route
        path="/recipient"
        element={(
          <ProtectedLayout roles={['RECIPIENT']}>
            <RecipientPage />
          </ProtectedLayout>
        )}
      />

      <Route
        path="/notifications"
        element={(
          <ProtectedLayout>
            <NotificationsPage />
          </ProtectedLayout>
        )}
      />

      <Route
        path="/admin"
        element={<Navigate to="/admin/overview" replace />}
      />

      <Route
        path="/admin/overview"
        element={(
          <AdminWebsiteLayout>
            <AdminPage view="overview" />
          </AdminWebsiteLayout>
        )}
      />

      <Route
        path="/admin/requests"
        element={(
          <AdminWebsiteLayout>
            <AdminPage view="requests" />
          </AdminWebsiteLayout>
        )}
      />

      <Route
        path="/admin/users"
        element={(
          <AdminWebsiteLayout>
            <AdminPage view="users" />
          </AdminWebsiteLayout>
        )}
      />

      <Route
        path="/admin/operations"
        element={(
          <AdminWebsiteLayout>
            <AdminPage view="operations" />
          </AdminWebsiteLayout>
        )}
      />

      <Route path="*" element={<NotFoundPage />} />
    </Routes>
  );
}

function App() {
  return (
    <AuthProvider>
      <BrowserRouter>
        <AppRoutes />
      </BrowserRouter>
    </AuthProvider>
  );
}

export default App;
